export async function squareNumber(n: number): Promise<number> {
  return n * n;
}

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { squareNumber } = proxyActivities<typeof activities>({
  startToCloseTimeout: '1 minute',
});

export async function ParallelSquaresWorkflow(numbers: number[]): Promise<number> {
  const promises = numbers.map((n) => squareNumber(n));
  const results = await Promise.all(promises);
  return results.reduce((sum, n) => sum + n, 0);
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing environment variables for Temporal Cloud');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: {
      clientCertPair: undefined, // Using API Key instead
    },
    metadata: {
      'authorization': [`Bearer ${apiKey}`],
    },
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'parallel-squares-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  console.log('Worker started, polling parallel-squares-ts task queue');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { ParallelSquaresWorkflow } from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !namespace || !apiKey || !runId) {
    throw new Error('Missing environment variables for Temporal Cloud');
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `parallel-wf-${runId}`;

  const handle = await client.workflow.start(ParallelSquaresWorkflow, {
    taskQueue: 'parallel-squares-ts',
    workflowId,
    args: [[1, 2, 3, 4, 5]],
  });

  console.log(`Started workflow ${workflowId}`);

  const result = await handle.result();
  console.log(result);
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

